<template>
  <div class="add-material">
    <!-- 搜索框 -->
    <el-row style="margin-top: 5px; height: 30px">
      <el-col :span="24">
        <el-input size="mini" placeholder="目前仅支持搜索区位以及植物名录" v-model="queryParams.name" class="input-with-select">
          <el-button slot="append" icon="el-icon-search" @click="handleSearch"></el-button>
        </el-input>
      </el-col>
    </el-row>

    <el-row :gutter="10" class="main-content-row">
      <el-col :span="6" class="sidebar-col">
        <!-- 左侧分类导航 -->
        <SlideLeft
          ref="slideLeftRef"
          :parentCategoryId="categoryParentId"
          @handleParams="handleQuery"
          :collectionStatus="true"
          @handleCollectionList="collectionClick"
        />
      </el-col>

      <!-- 右侧素材展示区（3列网格） -->
      <el-col :span="18" class="content-col">
        <div class="content" :infinite-scroll-distance="10" :infinite-scroll-immediate="false" v-infinite-scroll="loadList">
          <div class="content-image" v-for="item in materialAllList" :key="item.id">
            <img :src="item.thumbnail" @click="handleDownload(item)" style="width: 100%; height: 100%; object-fit: contain" />
            <div class="icon-container">
              <i
                @click.stop="handleCollection(item, 0)"
                class="el-icon-star-on"
                style="font-size: 25px; color: orange"
                v-if="item.params !== null && item.params.collectionId !== null"
              ></i>
              <i v-else @click.stop="handleCollection(item, 1)" class="el-icon-star-off" style="font-size: 25px; color: white"></i>
            </div>
          </div>
        </div>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import SlideLeft from '@/components/SlideLeft.vue';
import { getProductList, getCollectionList, addCollection, deleteCollection } from '@/api/main';
import { downloadAndOpen } from '@/utils/cepio';

export default {
  name: 'AddMaterial',
  components: {
    SlideLeft
  },
  props: {
    categoryParentId: {
      type: String,
      default: '9'
    },
    lasterVersion: {
      type: String,
      default: null
    },
    currentVersion: {
      type: String,
      default: null
    }
  },
  data() {
    return {
      totalCount: 0,
      materialList: [],
      materialAllList: [],
      queryParams: {
        firstCategoryId: this.categoryParentId,
        categoryId: null,
        thirdCategoryId: null,
        fourCategoryId: null,
        name: null,
        pageNum: 1,
        pageSize: 20
      }
    };
  },
  methods: {
    async handleQuery(params) {
      this.queryParams = { ...params, firstCategoryId: this.categoryParentId, pageNum: 1, pageSize: 20 }; // 更新查询参数
      await this.getMaterials();
      this.materialAllList = this.materialList;
    },
    async getMaterials() {
      try {
        const response = await getProductList(this.queryParams);
        this.totalCount = response.data && response.data.total ? response.data.total : 0;
        this.materialList = response.data && response.data.records ? response.data.records : [];
      } catch (error) {
        console.error('获取素材列表失败:', error);
        this.materialList = [];
      }
    },
    async handleCollection(item, type) {
      if (type === 1) {
        let response = await addCollection({ productId: item.id });
        this.$message.success('收藏成功');
        this.$set(item, 'params', { ...item.params, collectionId: response.data });
      } else if (type === 0) {
        await deleteCollection({ id: item.params.collectionId });
        this.$set(item, 'params', null);
        this.$message.success('取消成功');
      }
    },
    async collectionClick() {
      await this.getCollections();
      this.materialAllList = this.materialList;
    },
    async getCollections() {
      this.queryParams.pageNum = 1;
      let response = await getCollectionList();
      this.materialList = response.data;
    },
    async loadList() {
      if (this.materialAllList.length >= this.totalCount) {
        return; // 没有更多数据了
      }
      this.queryParams.pageNum += 1;
      await this.getMaterials();
      this.materialAllList = this.materialAllList.concat(this.materialList);
    },
    async handleSearch() {
      if (!this.queryParams.name) {
        this.$message.error('搜索内容不能为空！');
        return;
      }
      this.queryParams.pageNum = 1;
      this.queryParams.categoryId = null;
      this.queryParams.thirdCategoryId = null;
      this.queryParams.fourCategoryId = null;
      await this.getMaterials();
      this.materialAllList = this.materialList;
    },
    async handleDownload(item) {
      try {
        await downloadAndOpen(item.highDefinition, 'sucai', null);
      } catch (error) {
        console.error('下载或打开失败:', error);
        this.$message.error('下载打开失败');
      }
    }
  }
};
</script>

